I got a basic version working of ForeignKeyAutocompleteTabularInline working by simply copying 3 fields from ForeignKeyAutocompleteAdmin: *related_search_fields*, *get_help_text*, and *formfield_for_dbfield*. It's missing the search input, but it's good enough for me at the time being. Here's what I have so far:

```
import six
from django.contrib import admin
from django.db import models
from django.utils.text import get_text_list
from django_extensions.admin import ForeignKeySearchInput

from django.utils.translation import ugettext as _


class ForeignKeyAutocompleteTabularInline(admin.TabularInline):
    related_search_fields = {}

    def get_help_text(self, field_name, model_name):
        searchable_fields = self.related_search_fields.get(field_name, None)
        if searchable_fields:
            help_kwargs = {
                'model_name': model_name,
                'field_list': get_text_list(searchable_fields, _('and')),
            }
            return _('Use the left field to do %(model_name)s lookups in the fields %(field_list)s.') % help_kwargs
        return ''

    def formfield_for_dbfield(self, db_field, **kwargs):
        """
        Overrides the default widget for Foreignkey fields if they are
        specified in the related_search_fields class attribute.
        """
        if isinstance(db_field, models.ForeignKey) and db_field.name in self.related_search_fields:
            model_name = db_field.rel.to._meta.object_name
            help_text = self.get_help_text(db_field.name, model_name)
            if kwargs.get('help_text'):
                help_text = six.u('%s %s' % (kwargs['help_text'], help_text))
            kwargs['widget'] = ForeignKeySearchInput(db_field.rel, self.related_search_fields[db_field.name])
            kwargs['help_text'] = help_text
        return super(ForeignKeyAutocompleteTabularInline, self).formfield_for_dbfield(db_field, **kwargs)

```

Sure! samplingrate = 16000

private void writeWaveHeader(ByteBuffer buffer, float samplingrate, int length) {
        /* RIFF Chunk. */
        buffer.put("RIFF".getBytes());
        buffer.putInt(36 + length + 2);
        buffer.put("WAVE".getBytes()); /* WAV format. */

        /* Format chunk. */
        buffer.put("fmt ".getBytes()); /* Begin of the format chunk. */
        buffer.putInt(16); /* Length of the Format chunk. */
        buffer.putShort((short)1); /* Format: 1 = Raw PCM (linear quantization). */
        buffer.putShort((short)1); /* Number of channels. */
        buffer.putInt((int)samplingrate); /* Samplingrate. */
        buffer.putInt((int)(samplingrate * 4)); /* Byte rate. */
        buffer.putShort((short)2); /* Size of frame. */
        buffer.putShort((short)AudioFrame.BITS_PER_SAMPLE) /* Bits per sample. */;

        /* Data chunk */
        buffer.put("data".getBytes()); /* Begin of the data chunk. */
        buffer.putInt(length); /* Length of the data chunk. */
    }

